#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Serialize packet_id using direct serialization
        stream << packet_id;

        // Serialize username with length prefix using prefixed adaptor
        stream << hexi::prefixed(username);

        // Serialize scores vector with count first using prefixed adaptor
        stream << hexi::prefixed(scores);

        // Serialize metadata as null-terminated string using null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer_adaptor with an empty vector
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);

    // Call packet.serialise(adaptor) to perform the serialization
    packet.serialise(adaptor);

    // Return the vector containing the serialized data
    return buffer;
}
```

## Explanation:

1. **Serialization Method Implementation**:
   - `packet_id`: Directly serialized using `stream << packet_id`
   - `username`: Serialized with length prefix using `hexi::prefixed(username)`
   - `scores`: Serialized with count prefix using `hexi::prefixed(scores)`
   - `metadata`: Serialized as null-terminated string using `hexi::null_terminated(metadata)`

2. **Buffer Adaptor Usage**:
   - Creates an empty `std::vector<uint8_t>` as the underlying buffer
   - Wraps it with `hexi::buffer_adaptor` to provide the serialization interface

3. **Serialization Process**:
   - Calls `packet.serialise(adaptor)` which internally uses the stream operators
   - The stream operators automatically handle the serialization format according to the adaptors used

4. **Return Value**:
   - Returns the populated vector containing the serialized binary data

This implementation follows the specified requirements and leverages the Hexi library's serialization framework as described in the reference materials.

