#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(const_cast<std::span<const uint8_t>>(buffer));

    NetworkPacket packet;

    // Read packet_id using default read
    adaptor.read(&packet.packet_id);

    // Read username using prefixed adaptor
    adaptor.read(packet.username, hexi::prefixed);

    // Read scores count
    uint32_t scores_count;
    adaptor.read(&scores_count);

    // Read scores vector using read_container
    packet.scores.resize(scores_count);
    adaptor.read_container(packet.scores);

    // Read metadata as null-terminated string
    adaptor.read(packet.metadata, hexi::null_terminated);

    // Skip remaining padding bytes
    adaptor.skip(adaptor.size());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(const_cast<std::span<const uint8_t>>(buffer));

    PacketInfo info;

    // Use span() to get zero-copy view of packet_id
    auto id_span = adaptor.span<uint32_t>(1);
    info.packet_id = *id_span.data();

    // Read username using prefixed adaptor to get string_view
    adaptor.read(info.username, hexi::prefixed);

    // Read scores count
    uint32_t scores_count;
    adaptor.read(&scores_count);

    // Skip scores vector without reading elements
