    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // 1. Create a buffer_adaptor from the input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // 2. Use the binary_stream to preview the first byte (data_type) without advancing the read pointer
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);
    result.data_type = 0; // Initialize in case error occurs

    // 3. Check if the buffer has enough data for the item_count and items using the size function
    if (stream.size() < 1) { // Need at least 1 byte for data_type
        return result;
    }

    // Peek the data_type without advancing read pointer
    stream.peek(&result.data_type);

    // Check if we have enough data for item_count (4 bytes) plus items
    if (stream.size() < 5) { // 1 byte (data_type) + 4 bytes (item_count)
        return result;
    }

    // 4. Read the item_count (uint32_t) and then read the items based on the data_type
    uint32_t item_count = 0;
    stream >> item_count;

    // Check if we have enough data for all items
    size_t required_size = 5 + (result.data_type == 0 ? item_count * 4 : item_count * 4);
    if (stream.size() < required_size) {
        return result;
    }

    // Read the items based on data_type
    if (result.data_type == 0) {
        result.int_items.reserve(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            uint32_t value = 0;
            stream >> value;
            result.int_items.push_back(value);
        }
    } else {
        result.float_items.reserve(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            float value = 0.0f;
            stream >> value;
            result.float_items.push_back(value);
        }
    }

    return result;
}

