template<size_t block_size = 1024>
void write_to_dynamic_buffer(hexi::dynamic_buffer<block_size>& buffer, uint32_t header, const std::vector<uint8_t>& data) {
    // Write header as 4-byte array
    uint8_t header_bytes[4];
    header_bytes[0] = (header >> 24) & 0xFF;
    header_bytes[1] = (header >> 16) & 0xFF;
    header_bytes[2] = (header >> 8) & 0xFF;
    header_bytes[3] = header & 0xFF;

    buffer.write(header_bytes, 4);

    // Write data array
    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

template<size_t block_size = 1024>
struct BufferData {
    uint32_t header;
    std::vector<uint8_t> data;
};

BufferData<> read_from_dynamic_buffer(hexi::dynamic_buffer<1024>& buffer, size_t data_length) {
    BufferData<> result;

    // Read header (4 bytes)
    uint8_t header_bytes[4];
    buffer.read(header_bytes, 4);

    // Convert 4 bytes to uint32_t
    result.header = (static_cast<uint32_t>(header_bytes[0]) << 24) |
                   (static_cast<uint32_t>(header_bytes[1]) << 16) |
                   (static_cast<uint32_t>(header_bytes[2]) << 8) |
                   static_cast<uint32_t>(header_bytes[3]);

    // Read data array
    result.data.resize(data_length);
    if (data_length > 0) {
        buffer.read(result.data.data(), data_length);
    }

    return result;
}
```

