std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a hexi::file_buffer object using the provided file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer was created successfully (no errors)
    if (!buffer) {
        return {}; // Return empty vector if file couldn't be opened
    }

    // Create a vector to store the header data with the specified size
    std::vector<uint8_t> header_data(header_size);

    // Use the copy method of file_buffer to copy header data without advancing read pointer
    // Ensure we don't read beyond the actual file size
    size_t bytes_to_copy = std::min(header_size, buffer.size());
    if (bytes_to_copy > 0) {
        buffer.copy(header_data.data(), bytes_to_copy);
    }

    // Return the vector containing the header data
    return header_data;
}
```

