using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    // Use the put method to write the value as a varint
    writer.put(value);
    // Return the number of bytes written (using total_write() method)
    return writer.total_write();
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    // Use the get method to read a varint from the stream
    return reader.get<T>();
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::byte> buffer;

    // Create a buffer_adaptor for the buffer
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(buffer);

    // Create a binary_stream using the buffer_adaptor
    hexi::pmc::binary_stream stream(adaptor);

    // Encode the value using the writer
    std::size_t bytes_written = stream.put(original_value);

    // Reset the read position to the beginning for decoding
    // Note: In a real implementation, we'd need to seek back to start
    // For this simplified version, we'll create a new reader

    // Create a new binary_stream_reader for the same buffer
    hexi::pmc::binary_stream_reader reader(adaptor);

    // Decode the value using the reader
    T decoded_value = reader.get<T>();

    // Compare the decoded value with the original value
    bool success = (decoded_value == original_value);

    return success;
}
```

