Based on the reference materials and detailed specifications, here's the complete implementation:

```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <string_view>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialize sensor_id directly
        adaptor.write(sensor_id);

        // Convert and write each temperature with runtime endianness conversion
        for (float temp : temperatures) {
            float converted_temp = hexi::endian::conditional_reverse(
                temp, 
                std::endian::native, 
                std::endian::little
            );
            adaptor.write(converted_temp);
        }

        // Convert and write pressure with runtime endianness conversion
        double converted_pressure = hexi::endian::conditional_reverse(
            pressure, 
            std::endian::native, 
            std::endian::little
        );
        adaptor.write(converted_pressure);
    }

    void deserialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor.read(sensor_id);

        // Read and convert each temperature using in-place conversion
        for (float& temp : temperatures) {
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read and convert pressure using in-place conversion
        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    // Create a buffer and binary stream for serialization
    std::vector<uint8_t> buffer;
    hexi::binary_stream stream(buffer);

    // Use the stream's serialise method to serialize the entire structure
    stream.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData result;

    // Create a binary stream for deserialization
    hexi::binary_stream stream(buffer);

    // Use the stream's deserialise method to deserialize the entire structure
    stream.deserialise(result);

    return result;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;

    // Create a binary stream for partial extraction
    hexi::binary_stream stream(buffer);

    // Use view to extract null-terminated sensor name string
    info.sensor_name = stream.view();

    // Use enforce_read_bounds to check if there's enough data before reading sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read the sensor_id directly
    stream.read(&info.sensor_id);

    // Skip the remaining data using skip
    stream.skip(buffer.size() - stream.total_read());

    return info;
}
